  1	import * as React from 'react';
  2	import {
  3	  FormGroup,
  4	  FormHelperText,
  5	  HelperText,
  6	  HelperTextItem,
  7	} from '@patternfly/react-core';
  8	import { FieldArray, useField } from 'formik';
  9	import { TextColumnFieldProps, TextColumnItemProps } from './text-column-types';
 10	import TextColumnItem from './TextColumnItem';
 11	import TextColumnItemWithDnd from './TextColumnItemWithDnd';
 12	import { useFormikValidationFix } from '../pipelines-details/multi-column-field/formik-validation-fix';
 13	import { getFieldId } from '../pipelines-details/multi-column-field/utils';
 14	import MultiColumnFieldFooter from '../pipelines-details/multi-column-field/MultiColumnFieldFooter';
 15	import { RedExclamationCircleIcon } from '@openshift-console/dynamic-plugin-sdk';
 16	
 17	const TextColumnField: React.FC<TextColumnFieldProps> = (props) => {
 18	  const {
 19	    required,
 20	    name,
 21	    label,
 22	    addLabel,
 23	    helpText,
 24	    isReadOnly,
 25	    onChange,
 26	    children,
 27	    dndEnabled = false,
 28	  } = props;
 29	  const [field, { touched, error }] = useField<string[]>(name);
 30	  useFormikValidationFix(field.value);
 31	  const rowValues = field.value ?? [];
 32	  const fieldId = getFieldId(name, 'single-column');
 33	  const isValid = !(touched && error);
 34	  const getTextColumnProps = (colProps: TextColumnItemProps) => {
 35	    return { ...colProps, key: `${colProps.idx.toString()}` };
 36	  };
 37	
 38	  return (
 39	    <FieldArray
 40	      name={name}
 41	      render={(arrayHelpers) => (
 42	        <>
 43	          <FormGroup
 44	            fieldId={fieldId}
 45	            label={label}
 46	            isRequired={required}
 47	            data-test={props['data-test'] || 'text-column-field'}
 48	          >
 49	            {dndEnabled ? (
 50	              <>
 51	                {rowValues.map((v, idx) => {
 52	                  return (
 53	                    <TextColumnItemWithDnd
 54	                      key={idx}
 55	                      {...getTextColumnProps({
 56	                        ...props,
 57	                        rowValues,
 58	                        idx,
 59	                        arrayHelpers,
 60	                      })}
 61	                    >
 62	                      {children}
 63	                    </TextColumnItemWithDnd>
 64	                  );
 65	                })}
 66	              </>
 67	            ) : (
 68	              <>
 69	                {rowValues.map((v, idx) => {
 70	                  return (
 71	                    <TextColumnItem
 72	                      key={idx}
 73	                      {...getTextColumnProps({
 74	                        ...props,
 75	                        rowValues,
 76	                        idx,
 77	                        arrayHelpers,
 78	                      })}
 79	                    >
 80	                      {children}
 81	                    </TextColumnItem>
 82	                  );
 83	                })}
 84	              </>
 85	            )}
 86	            {!isReadOnly && (
 87	              <MultiColumnFieldFooter
 88	                addLabel={addLabel}
 89	                onAdd={() => {
 90	                  arrayHelpers.push('');
 91	                  onChange && onChange([...rowValues, '']);
 92	                }}
 93	              />
 94	            )}
 95	
 96	            <FormHelperText>
 97	              <HelperText>
 98	                {!isValid ? (
 99	                  <HelperTextItem
100	                    variant="error"
101	                    icon={<RedExclamationCircleIcon />}
102	                  >
103	                    {error}
104	                  </HelperTextItem>
105	                ) : (
106	                  <HelperTextItem>{helpText}</HelperTextItem>
107	                )}
108	              </HelperText>
109	            </FormHelperText>
110	          </FormGroup>
111	        </>
112	      )}
113	    />
114	  );
115	};
116	export default TextColumnField;

